parameters.jsCode:
// ---- MOCK QUICKBOOKS PULL ----
// DEMO ONLY. Returns a realistic month of financials for ONE client.
// Flip SCENARIO to see the two paths:
//   'clean' -> data is good, nothing material -> report auto-assembles.
//   'held'  -> dirty data + cash runway below floor -> report is HELD for a human.
// LIVE: delete this node and pull from QuickBooks Online (P&L, Balance Sheet,
//       prior period, budget) + a categorization/reconciliation read.

const SCENARIO = 'clean'; // <-- change to 'held' for the money-shot demo

const clean = {
  client_name: 'Meridian Design Co.',
  period_label: 'June 2026',
  current: { revenue: 182400, cogs: 71100, opex: 84300, cash_balance: 246000,
    expenses: { payroll: 52000, software: 6100, marketing: 12400, rent: 9800, other: 4000 } },
  prior:   { revenue: 175800, cogs: 69200, opex: 83100,
    expenses: { payroll: 51500, software: 5900, marketing: 11800, rent: 9800, other: 4100 } },
  budget:  { revenue: 178000, opex: 85000 },
  data_quality: { uncategorized_pct: 1.4, accounts_reconciled: true, has_prior: true, has_budget: true },
  kpis: [ { name: 'Gross margin %', value: 61.0, expected_min: 55, expected_max: 68 },
          { name: 'MRR churn %', value: 2.1, expected_min: 0, expected_max: 5 } ]
};

const held = {
  client_name: 'Northwind Logistics LLC',
  period_label: 'June 2026',
  current: { revenue: 148200, cogs: 96500, opex: 71000, cash_balance: 51000,
    expenses: { payroll: 41000, fuel: 18900, software: 3200, rent: 5600, other: 2300 } },
  prior:   { revenue: 151000, cogs: 88000, opex: 62000,
    expenses: { payroll: 40500, fuel: 11200, software: 3100, rent: 5600, other: 1600 } },
  budget:  { revenue: 155000, opex: 64000 },
  data_quality: { uncategorized_pct: 22.0, accounts_reconciled: false, has_prior: true, has_budget: true },
  kpis: [ { name: 'Gross margin %', value: 34.9, expected_min: 40, expected_max: 55 } ]
};

return [{ json: SCENARIO === 'held' ? held : clean }];

// ---- NORMALIZE + COMPUTE METRICS (deterministic — NOT the LLM) ----
// All arithmetic happens here so figures are exact, reproducible, auditable.
// The model never computes anything; it only describes these numbers later.
const d = $json;
const c = d.current, p = d.prior, b = d.budget || {};
const pct = (a, base) => (base ? +(((a - base) / base) * 100).toFixed(1) : null);

const grossMargin = c.revenue ? +(((c.revenue - c.cogs) / c.revenue) * 100).toFixed(1) : null;
const priorMargin = p.revenue ? +(((p.revenue - p.cogs) / p.revenue) * 100).toFixed(1) : null;
const netIncome = c.revenue - c.cogs - c.opex;
const priorNet  = p.revenue - p.cogs - p.opex;

// Approx cash runway: months of net burn the cash covers. Profitable => 'healthy'.
const netBurn = (c.cogs + c.opex) - c.revenue; // positive = burning cash
const runwayMonths = netBurn > 0 ? +(c.cash_balance / netBurn).toFixed(1) : 99; // 99 = healthy/not burning

// Largest expense category swings vs prior (by % change).
const swings = Object.keys(c.expenses || {}).map(k => {
  const cur = c.expenses[k], pr = (p.expenses || {})[k] || 0;
  return { category: k, pct: pr ? +(((cur - pr) / pr) * 100).toFixed(1) : null, cur, pr };
}).filter(x => x.pct !== null).sort((a, z) => Math.abs(z.pct) - Math.abs(a.pct));
const topSwings = swings.slice(0, 3);

return [{ json: {
  client_name: d.client_name,
  period_label: d.period_label,
  revenue: c.revenue,
  revenue_mom_pct: pct(c.revenue, p.revenue),
  revenue_vs_budget_pct: b.revenue ? pct(c.revenue, b.revenue) : null,
  gross_margin_pct: grossMargin,
  gross_margin_prior_pct: priorMargin,
  margin_delta_pts: (grossMargin !== null && priorMargin !== null) ? +(grossMargin - priorMargin).toFixed(1) : null,
  opex: c.opex,
  opex_mom_pct: pct(c.opex, p.opex),
  opex_vs_budget_pct: b.opex ? pct(c.opex, b.opex) : null,
  net_income: netIncome,
  net_income_mom_pct: pct(netIncome, priorNet),
  cash_balance: c.cash_balance,
  runway_months: runwayMonths,
  top_expense_swings: topSwings,
  top_expense_swings_text: topSwings.map(s => `${s.category} ${s.pct > 0 ? '+' : ''}${s.pct}%`).join(', '),
  kpis: d.kpis || [],
  kpi_summary: (d.kpis || []).map(k => `${k.name}: ${k.value}`).join('; '),
  data_quality: d.data_quality || {}
} }];

// ---- GATE 1: DATA-QUALITY GATE ----
// Before we will build a client-facing report AT ALL, confirm the data is
// trustworthy. Reporting on unfinished books is the worst failure mode here.
// Thresholds are CONFIG the firm tunes — not hard logic.
const UNCATEGORIZED_LIMIT_PCT = 10; // firm-set: max % of txns allowed in Uncategorized

const j = $json;
const dq = j.data_quality || {};
const dqReasons = [];

if ((dq.uncategorized_pct ?? 100) > UNCATEGORIZED_LIMIT_PCT)
  dqReasons.push(`uncategorized ${dq.uncategorized_pct}% > ${UNCATEGORIZED_LIMIT_PCT}% limit`);
if (dq.accounts_reconciled === false) dqReasons.push('key accounts not reconciled');
if (dq.has_prior === false) dqReasons.push('missing prior period (no comparison possible)');
if (dq.has_budget === false) dqReasons.push('missing budget');

const dqPass = dqReasons.length === 0;

return [{ json: { ...j,
  uncategorized_pct: dq.uncategorized_pct ?? null,
  uncategorized_limit_pct: UNCATEGORIZED_LIMIT_PCT,
  accounts_reconciled: dq.accounts_reconciled ?? null,
  has_prior: dq.has_prior ?? null,
  has_budget: dq.has_budget ?? null,
  dq_pass: dqPass,
  dq_reasons: dqReasons
} }];

// ---- GATE 2: MATERIALITY GATE + FINAL DECISION ----
// Deterministic anomaly checks against firm-set thresholds. If nothing is
// material AND the data is clean, the report is safe to auto-deliver.
// If anything is material, hold for a human (draft is still produced).
// Thresholds are CONFIG the firm tunes per client.
const RUNWAY_FLOOR_MONTHS   = 3;   // hold if cash runway drops below this
const REVENUE_MOVE_PCT       = 20; // hold if |revenue MoM| >= this
const REVENUE_BUDGET_MISS_PCT= 15; // hold if revenue is this far under budget
const MARGIN_DROP_PTS        = 5;  // hold if gross margin fell this many points
const EXPENSE_SPIKE_PCT      = 40; // hold if any expense category swung this much

const j = $json;
const flags = [];

if (j.runway_months !== null && j.runway_months < RUNWAY_FLOOR_MONTHS)
  flags.push(`cash runway ${j.runway_months} mo below ${RUNWAY_FLOOR_MONTHS}-mo floor`);
if (j.revenue_mom_pct !== null && Math.abs(j.revenue_mom_pct) >= REVENUE_MOVE_PCT)
  flags.push(`revenue moved ${j.revenue_mom_pct}% MoM (>= ${REVENUE_MOVE_PCT}%)`);
if (j.revenue_vs_budget_pct !== null && j.revenue_vs_budget_pct <= -REVENUE_BUDGET_MISS_PCT)
  flags.push(`revenue ${j.revenue_vs_budget_pct}% vs budget (missed by >= ${REVENUE_BUDGET_MISS_PCT}%)`);
if (j.margin_delta_pts !== null && j.margin_delta_pts <= -MARGIN_DROP_PTS)
  flags.push(`gross margin fell ${Math.abs(j.margin_delta_pts)} pts`);
(j.top_expense_swings || []).forEach(s => {
  if (s.pct !== null && Math.abs(s.pct) >= EXPENSE_SPIKE_PCT)
    flags.push(`${s.category} expense swung ${s.pct > 0 ? '+' : ''}${s.pct}%`);
});
(j.kpis || []).forEach(k => {
  if (k.value < k.expected_min || k.value > k.expected_max)
    flags.push(`${k.name} = ${k.value} outside expected ${k.expected_min}-${k.expected_max}`);
});

const materialPass = flags.length === 0;
const deliver = j.dq_pass && materialPass;

let gateTripped = 'none';
if (!j.dq_pass && !materialPass) gateTripped = 'both';
else if (!j.dq_pass) gateTripped = 'data_quality';
else if (!materialPass) gateTripped = 'materiality';

const allFlags = [...(j.dq_reasons || []), ...flags];

return [{ json: { ...j,
  runway_floor: RUNWAY_FLOOR_MONTHS,
  material_flags: flags,
  material_pass: materialPass,
  material_flags_text: allFlags.join('; ') || 'none',
  decision: deliver ? 'deliver' : 'hold',
  gate_tripped: gateTripped
} }];

