// ---- ASSEMBLE REPORT ----
// Parse the narrative defensively and build the final report object.
// If the draft fails to parse, force a hold — never ship an empty report.
const g = $('Gate 2 · Materiality + Decision').item.json;

let n = { headline: '', narrative: '', kpi_callouts: [], watch_items: [] };
try {
  const c = $json;
  const txt = c.message?.content ?? c.content ?? c.text ?? JSON.stringify(c);
  n = typeof txt === 'string' ? JSON.parse(txt) : txt;
} catch (e) { /* leave empty -> narrativeValid false -> hold */ }

const narrativeValid = (n.narrative || '').length > 40 && (n.headline || '').length > 0;

return [{ json: { ...g,
  report: {
    client: g.client_name, period: g.period_label,
    headline: n.headline, narrative: n.narrative,
    kpi_callouts: n.kpi_callouts || [], watch_items: n.watch_items || [],
    figures: {
      revenue: g.revenue, revenue_mom_pct: g.revenue_mom_pct,
      gross_margin_pct: g.gross_margin_pct, net_income: g.net_income,
      cash_balance: g.cash_balance, runway_months: g.runway_months
    }
  },
  narrativeValid
} }];

