// Parse the reviewer summary defensively.
const a = $('Assemble Report').item.json;
let h = { one_liner: '', action_items: [], severity: a.gate_tripped };
try {
  const c = $json;
  const txt = c.message?.content ?? c.content ?? c.text ?? JSON.stringify(c);
  h = typeof txt === 'string' ? JSON.parse(txt) : txt;
} catch (e) { h.one_liner = 'Held: ' + (a.material_flags_text || 'review needed'); }
return [{ json: { ...a, hold_one_liner: h.one_liner, hold_actions: h.action_items || [], hold_severity: h.severity } }];

