// ---- LOG RUN (write-back / measurement) ----
// Both paths land here. In a live build, append this row to a Google Sheet
// or a database so the firm can see auto-delivered vs held, which gate tripped,
// and estimated hours saved per client per month.
const j = $json;
const ESTIMATED_HOURS_SAVED_PER_REPORT = 6; // firm's manual-assembly baseline
return [{ json: {
  logged_at: new Date().toISOString(),
  client: j.client_name,
  period: j.period_label,
  outcome: j.decision === 'deliver' && j.narrativeValid ? 'auto_assembled' : 'held_for_review',
  gate_tripped: j.gate_tripped,
  flags: j.material_flags_text,
  hours_saved_estimate: ESTIMATED_HOURS_SAVED_PER_REPORT,
  runway_months: j.runway_months,
  revenue_mom_pct: j.revenue_mom_pct
} }];
